import { Component, Prop, State, Event, EventEmitter, h, Watch, Element } from '@stencil/core';

// ============================================================================
// Types
// ============================================================================

export type DataGridColumnType = 'text' | 'number' | 'date' | 'boolean' | 'custom';
export type DataGridSortDirection = 'asc' | 'desc' | null;
export type DataGridSelectionMode = 'none' | 'single' | 'multiple';
export type DataGridEditMode = 'none' | 'cell' | 'row' | 'popup';
export type DataGridFilterOperator =
  | 'contains'
  | 'equals'
  | 'startsWith'
  | 'endsWith'
  | 'greaterThan'
  | 'lessThan'
  | 'greaterThanOrEqual'
  | 'lessThanOrEqual'
  | 'between'
  | 'isEmpty'
  | 'isNotEmpty';

export interface DataGridColumn<T = unknown> {
  /** Unique identifier for the column */
  id: string;
  /** Header text to display */
  header: string;
  /** Property key to access data (supports dot notation: 'user.name') */
  accessor: keyof T | string;
  /** Column data type for filtering and formatting */
  type?: DataGridColumnType;
  /** Column width (px, %, or 'auto') */
  width?: string | number;
  /** Minimum column width */
  minWidth?: number;
  /** Enable sorting for this column */
  sortable?: boolean;
  /** Enable filtering for this column */
  filterable?: boolean;
  /** Enable editing for this column */
  editable?: boolean;
  /** Text alignment */
  align?: 'left' | 'center' | 'right';
  /** Custom cell render function (returns HTML string or VNode) */
  cellRenderer?: (value: unknown, row: T, rowIndex: number) => unknown;
  /** Custom header render function */
  headerRenderer?: (column: DataGridColumn<T>) => unknown;
  /** Custom edit cell render function */
  editCellRenderer?: (value: unknown, row: T, rowIndex: number, onChange: (newValue: unknown) => void) => unknown;
  /** Whether column is visible */
  visible?: boolean;
  /** Pin column to left or right */
  pinned?: 'left' | 'right' | null;
}

export interface DataGridSortState {
  columnId: string;
  direction: DataGridSortDirection;
}

export interface DataGridFilterState {
  columnId: string;
  operator: DataGridFilterOperator;
  value: unknown;
  valueTo?: unknown; // For 'between' operator
}

export interface DataGridGroupState {
  columnId: string;
  expanded: Set<string>;
}

export interface DataGridRowSelection {
  selectedRows: Set<string | number>;
  isAllSelected: boolean;
  isIndeterminate: boolean;
}

export interface DataGridGroup {
  key: string;
  value: unknown;
  displayValue: string;
  rows: unknown[];
  depth: number;
  columnId: string;
}

export interface DataGridEditState {
  rowKey: string | number;
  columnId: string | null; // null means entire row is being edited
  originalValue: unknown;
  currentValue: unknown;
}

export interface DataGridRowChanges {
  rowKey: string | number;
  rowIndex: number;
  originalRow: unknown;
  changes: Record<string, unknown>;
}

// ============================================================================
// Component
// ============================================================================

@Component({
  tag: 'bh-data-grid',
  styleUrl: 'bh-data-grid.css',
  shadow: true,
})
export class BhDataGrid {
  @Element() el!: HTMLElement;

  // -------------------------------------------------------------------------
  // Props - Data
  // -------------------------------------------------------------------------

  /** Array of data objects to display */
  @Prop() data: unknown[] = [];

  /** Column definitions */
  @Prop() columns: DataGridColumn[] = [];

  /** Unique identifier property for each row (for selection tracking) */
  @Prop() rowKey: string = 'id';

  // -------------------------------------------------------------------------
  // Props - Selection
  // -------------------------------------------------------------------------

  /** Enable row selection */
  @Prop() enableSelection: boolean = false;

  /** Selection mode */
  @Prop() selectionMode: DataGridSelectionMode = 'multiple';

  /** Currently selected row keys (controlled) */
  @Prop({ mutable: true }) selectedKeys: (string | number)[] = [];

  // -------------------------------------------------------------------------
  // Props - Sorting
  // -------------------------------------------------------------------------

  /** Enable sorting */
  @Prop() enableSorting: boolean = true;

  /** Allow multi-column sorting */
  @Prop() multiSort: boolean = false;

  /** Current sort state (controlled) */
  @Prop({ mutable: true }) sortState: DataGridSortState[] = [];

  // -------------------------------------------------------------------------
  // Props - Filtering
  // -------------------------------------------------------------------------

  /** Enable filtering */
  @Prop() enableFiltering: boolean = false;

  /** Show filter row below header */
  @Prop() showFilterRow: boolean = false;

  /** Current filter state (controlled) */
  @Prop({ mutable: true }) filterState: DataGridFilterState[] = [];

  // -------------------------------------------------------------------------
  // Props - Grouping
  // -------------------------------------------------------------------------

  /** Enable row grouping */
  @Prop() enableGrouping: boolean = false;

  /** Columns to group by */
  @Prop() groupBy: string[] = [];

  // -------------------------------------------------------------------------
  // Props - Editing
  // -------------------------------------------------------------------------

  /** Enable editing */
  @Prop() enableEditing: boolean = false;

  /** Edit mode: cell (individual cells), row (entire row), popup (modal form) */
  @Prop() editMode: DataGridEditMode = 'cell';

  /** Whether to show edit/save/cancel buttons in row actions */
  @Prop() showEditActions: boolean = true;

  // -------------------------------------------------------------------------
  // Props - Display
  // -------------------------------------------------------------------------

  /** Show header row */
  @Prop() showHeader: boolean = true;

  /** Show row borders */
  @Prop() showRowBorders: boolean = true;

  /** Striped rows */
  @Prop() striped: boolean = false;

  /** Compact row height */
  @Prop() compact: boolean = false;

  /** Empty state message */
  @Prop() emptyMessage: string = 'No data available';

  /** Loading state */
  @Prop() loading: boolean = false;

  // -------------------------------------------------------------------------
  // State
  // -------------------------------------------------------------------------

  @State() internalSelectedKeys: Set<string | number> = new Set();
  @State() internalSortState: DataGridSortState[] = [];
  @State() internalFilterState: DataGridFilterState[] = [];
  @State() expandedGroups: string[] = [];
  @State() hoveredRowIndex: number | null = null;
  @State() filterInputValues: Record<string, string> = {};

  // Editing state
  @State() editingRowKey: string | number | null = null;
  @State() editingColumnId: string | null = null;
  @State() editingValues: Record<string, unknown> = {};
  @State() showEditPopup: boolean = false;

  // Filter popover state
  @State() activeFilterColumn: string | null = null;

  // -------------------------------------------------------------------------
  // Events
  // -------------------------------------------------------------------------

  /** Emitted when row selection changes */
  @Event() bhSelectionChange!: EventEmitter<{ selectedKeys: (string | number)[]; selectedRows: unknown[] }>;

  /** Emitted when sort state changes */
  @Event() bhSortChange!: EventEmitter<DataGridSortState[]>;

  /** Emitted when filter state changes */
  @Event() bhFilterChange!: EventEmitter<DataGridFilterState[]>;

  /** Emitted when a row is clicked */
  @Event() bhRowClick!: EventEmitter<{ row: unknown; rowIndex: number; rowKey: string | number }>;

  /** Emitted when a cell is clicked */
  @Event() bhCellClick!: EventEmitter<{ row: unknown; column: DataGridColumn; value: unknown; rowIndex: number; columnIndex: number }>;

  /** Emitted when group expand/collapse changes */
  @Event() bhGroupToggle!: EventEmitter<{ groupKey: string; expanded: boolean }>;

  /** Emitted when editing starts */
  @Event() bhEditStart!: EventEmitter<{ rowKey: string | number; row: unknown; columnId?: string }>;

  /** Emitted when editing is cancelled */
  @Event() bhEditCancel!: EventEmitter<{ rowKey: string | number; row: unknown }>;

  /** Emitted when changes are saved */
  @Event() bhEditSave!: EventEmitter<DataGridRowChanges>;

  /** Emitted when a cell value changes during editing (before save) */
  @Event() bhCellChange!: EventEmitter<{ rowKey: string | number; columnId: string; oldValue: unknown; newValue: unknown }>;

  // -------------------------------------------------------------------------
  // Watchers
  // -------------------------------------------------------------------------

  @Watch('selectedKeys')
  handleSelectedKeysChange(newValue: (string | number)[]) {
    this.internalSelectedKeys = new Set(newValue);
  }

  @Watch('sortState')
  handleSortStateChange(newValue: DataGridSortState[]) {
    this.internalSortState = [...newValue];
  }

  @Watch('filterState')
  handleFilterStateChange(newValue: DataGridFilterState[]) {
    this.internalFilterState = [...newValue];
  }

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  componentWillLoad() {
    this.internalSelectedKeys = new Set(this.selectedKeys);
    this.internalSortState = [...this.sortState];
    this.internalFilterState = [...this.filterState];
  }

  // -------------------------------------------------------------------------
  // Helpers
  // -------------------------------------------------------------------------

  private getRowKey(row: unknown, index: number): string | number {
    if (typeof row === 'object' && row !== null && this.rowKey in row) {
      return (row as Record<string, unknown>)[this.rowKey] as string | number;
    }
    return index;
  }

  private getCellValue(row: unknown, accessor: string): unknown {
    if (typeof row !== 'object' || row === null) return undefined;

    // Support dot notation for nested properties
    const keys = accessor.split('.');
    let value: unknown = row;

    for (const key of keys) {
      if (typeof value === 'object' && value !== null && key in value) {
        value = (value as Record<string, unknown>)[key];
      } else {
        return undefined;
      }
    }

    return value;
  }

  private getVisibleColumns(): DataGridColumn[] {
    return this.columns.filter(col => col.visible !== false);
  }

  // -------------------------------------------------------------------------
  // Data Processing
  // -------------------------------------------------------------------------

  private getProcessedData(): unknown[] {
    let processedData = [...this.data];

    // Apply filtering
    if (this.enableFiltering && this.internalFilterState.length > 0) {
      processedData = this.applyFilters(processedData);
    }

    // Apply sorting
    if (this.enableSorting && this.internalSortState.length > 0) {
      processedData = this.applySorting(processedData);
    }

    return processedData;
  }

  private applyFilters(data: unknown[]): unknown[] {
    return data.filter(row => {
      return this.internalFilterState.every(filter => {
        const column = this.columns.find(c => c.id === filter.columnId);
        if (!column) return true;

        const value = this.getCellValue(row, column.accessor as string);
        return this.matchesFilter(value, filter, column.type);
      });
    });
  }

  private matchesFilter(value: unknown, filter: DataGridFilterState, type?: DataGridColumnType): boolean {
    if (filter.operator === 'isEmpty') {
      return value === null || value === undefined || value === '';
    }
    if (filter.operator === 'isNotEmpty') {
      return value !== null && value !== undefined && value !== '';
    }

    const filterValue = filter.value;

    if (type === 'number') {
      const numValue = Number(value);
      const numFilter = Number(filterValue);

      switch (filter.operator) {
        case 'equals': return numValue === numFilter;
        case 'greaterThan': return numValue > numFilter;
        case 'lessThan': return numValue < numFilter;
        case 'greaterThanOrEqual': return numValue >= numFilter;
        case 'lessThanOrEqual': return numValue <= numFilter;
        case 'between': return numValue >= numFilter && numValue <= Number(filter.valueTo);
        default: return true;
      }
    }

    if (type === 'date') {
      const dateValue = new Date(value as string).getTime();
      const dateFilter = new Date(filterValue as string).getTime();

      switch (filter.operator) {
        case 'equals': return dateValue === dateFilter;
        case 'greaterThan': return dateValue > dateFilter;
        case 'lessThan': return dateValue < dateFilter;
        case 'between': {
          const dateTo = new Date(filter.valueTo as string).getTime();
          return dateValue >= dateFilter && dateValue <= dateTo;
        }
        default: return true;
      }
    }

    // Text filtering
    const strValue = String(value ?? '').toLowerCase();
    const strFilter = String(filterValue ?? '').toLowerCase();

    switch (filter.operator) {
      case 'contains': return strValue.includes(strFilter);
      case 'equals': return strValue === strFilter;
      case 'startsWith': return strValue.startsWith(strFilter);
      case 'endsWith': return strValue.endsWith(strFilter);
      default: return true;
    }
  }

  private applySorting(data: unknown[]): unknown[] {
    if (this.internalSortState.length === 0) return data;

    return [...data].sort((a, b) => {
      for (const sort of this.internalSortState) {
        const column = this.columns.find(c => c.id === sort.columnId);
        if (!column || !sort.direction) continue;

        const aValue = this.getCellValue(a, column.accessor as string);
        const bValue = this.getCellValue(b, column.accessor as string);

        let comparison = 0;

        if (column.type === 'number') {
          comparison = (Number(aValue) || 0) - (Number(bValue) || 0);
        } else if (column.type === 'date') {
          comparison = new Date(aValue as string).getTime() - new Date(bValue as string).getTime();
        } else {
          comparison = String(aValue ?? '').localeCompare(String(bValue ?? ''));
        }

        if (comparison !== 0) {
          return sort.direction === 'desc' ? -comparison : comparison;
        }
      }
      return 0;
    });
  }

  // -------------------------------------------------------------------------
  // Grouping Logic
  // -------------------------------------------------------------------------

  private getGroupedData(data: unknown[]): DataGridGroup[] {
    if (!this.enableGrouping || this.groupBy.length === 0) {
      return [];
    }

    return this.groupByColumn(data, this.groupBy[0], 0);
  }

  private groupByColumn(data: unknown[], columnId: string, depth: number): DataGridGroup[] {
    const column = this.columns.find(c => c.id === columnId);
    if (!column) return [];

    const groups = new Map<string, unknown[]>();

    for (const row of data) {
      const value = this.getCellValue(row, column.accessor as string);
      const key = String(value ?? '(Empty)');

      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }

    const result: DataGridGroup[] = [];

    for (const [key, rows] of groups) {
      const groupKey = `${columnId}:${key}`;
      result.push({
        key: groupKey,
        value: key,
        displayValue: key,
        rows,
        depth,
        columnId,
      });
    }

    // Sort groups alphabetically
    result.sort((a, b) => String(a.displayValue).localeCompare(String(b.displayValue)));

    return result;
  }

  private handleGroupToggle = (groupKey: string) => {
    const isCurrentlyExpanded = this.expandedGroups.includes(groupKey);

    if (isCurrentlyExpanded) {
      this.expandedGroups = this.expandedGroups.filter(key => key !== groupKey);
    } else {
      this.expandedGroups = [...this.expandedGroups, groupKey];
    }

    this.bhGroupToggle.emit({ groupKey, expanded: !isCurrentlyExpanded });
  };

  // -------------------------------------------------------------------------
  // Selection Handlers
  // -------------------------------------------------------------------------

  private handleSelectAll = () => {
    const processedData = this.getProcessedData();
    const allKeys = processedData.map((row, i) => this.getRowKey(row, i));

    const isAllSelected = allKeys.every(key => this.internalSelectedKeys.has(key));

    if (isAllSelected) {
      this.internalSelectedKeys = new Set();
    } else {
      this.internalSelectedKeys = new Set(allKeys);
    }

    this.emitSelectionChange();
  };

  private handleRowSelect = (row: unknown, rowIndex: number) => {
    const key = this.getRowKey(row, rowIndex);

    if (this.selectionMode === 'single') {
      if (this.internalSelectedKeys.has(key)) {
        this.internalSelectedKeys = new Set();
      } else {
        this.internalSelectedKeys = new Set([key]);
      }
    } else {
      const newSet = new Set(this.internalSelectedKeys);
      if (newSet.has(key)) {
        newSet.delete(key);
      } else {
        newSet.add(key);
      }
      this.internalSelectedKeys = newSet;
    }

    this.emitSelectionChange();
  };

  private emitSelectionChange() {
    const selectedKeys = Array.from(this.internalSelectedKeys);
    const selectedRows = this.data.filter((row, i) =>
      this.internalSelectedKeys.has(this.getRowKey(row, i))
    );

    this.selectedKeys = selectedKeys;
    this.bhSelectionChange.emit({ selectedKeys, selectedRows });
  }

  private getSelectionState(): DataGridRowSelection {
    const processedData = this.getProcessedData();
    const allKeys = processedData.map((row, i) => this.getRowKey(row, i));
    const selectedCount = allKeys.filter(key => this.internalSelectedKeys.has(key)).length;

    return {
      selectedRows: this.internalSelectedKeys,
      isAllSelected: selectedCount === allKeys.length && allKeys.length > 0,
      isIndeterminate: selectedCount > 0 && selectedCount < allKeys.length,
    };
  }

  // -------------------------------------------------------------------------
  // Sort Handlers
  // -------------------------------------------------------------------------

  private handleSort = (column: DataGridColumn) => {
    if (!this.enableSorting || column.sortable === false) return;

    const existingSort = this.internalSortState.find(s => s.columnId === column.id);
    let newDirection: DataGridSortDirection = 'asc';

    if (existingSort) {
      if (existingSort.direction === 'asc') {
        newDirection = 'desc';
      } else if (existingSort.direction === 'desc') {
        newDirection = null;
      }
    }

    let newSortState: DataGridSortState[];

    if (this.multiSort) {
      newSortState = this.internalSortState.filter(s => s.columnId !== column.id);
      if (newDirection) {
        newSortState.push({ columnId: column.id, direction: newDirection });
      }
    } else {
      newSortState = newDirection ? [{ columnId: column.id, direction: newDirection }] : [];
    }

    this.internalSortState = newSortState;
    this.sortState = newSortState;
    this.bhSortChange.emit(newSortState);
  };

  private getSortDirection(columnId: string): DataGridSortDirection {
    const sort = this.internalSortState.find(s => s.columnId === columnId);
    return sort?.direction ?? null;
  }

  // -------------------------------------------------------------------------
  // Filter Handlers
  // -------------------------------------------------------------------------

  private handleFilterInput = (column: DataGridColumn, value: string) => {
    this.filterInputValues = { ...this.filterInputValues, [column.id]: value };

    // Debounced filter application
    const newFilterState = this.internalFilterState.filter(f => f.columnId !== column.id);

    if (value.trim()) {
      newFilterState.push({
        columnId: column.id,
        operator: column.type === 'number' ? 'equals' : column.type === 'date' ? 'equals' : 'contains',
        value: value.trim(),
      });
    }

    this.internalFilterState = newFilterState;
    this.filterState = newFilterState;
    this.bhFilterChange.emit(newFilterState);
  };

  private toggleFilterPopover = (columnId: string) => {
    if (this.activeFilterColumn === columnId) {
      this.activeFilterColumn = null;
    } else {
      this.activeFilterColumn = columnId;
    }
  };

  // -------------------------------------------------------------------------
  // Row/Cell Handlers
  // -------------------------------------------------------------------------

  private handleRowClick = (row: unknown, rowIndex: number) => {
    const rowKey = this.getRowKey(row, rowIndex);
    this.bhRowClick.emit({ row, rowIndex, rowKey });
  };

  private handleCellClick = (row: unknown, column: DataGridColumn, rowIndex: number, columnIndex: number) => {
    const value = this.getCellValue(row, column.accessor as string);
    this.bhCellClick.emit({ row, column, value, rowIndex, columnIndex });
  };

  // -------------------------------------------------------------------------
  // Render Methods
  // -------------------------------------------------------------------------

  private renderHeader() {
    if (!this.showHeader) return null;

    const visibleColumns = this.getVisibleColumns();
    const selectionState = this.getSelectionState();

    return (
      <div class="data-grid-header-row" role="row">
        {this.enableSelection && (
          <div class="data-grid-header-cell data-grid-cell-checkbox" role="columnheader">
            <bh-checkbox
              size="sm"
              checked={selectionState.isAllSelected}
              indeterminate={selectionState.isIndeterminate}
              onBhChange={() => this.handleSelectAll()}
            />
          </div>
        )}
        {visibleColumns.map((column) => this.renderHeaderCell(column))}
      </div>
    );
  }

  private renderHeaderCell(column: DataGridColumn) {
    const sortDirection = this.getSortDirection(column.id);
    const isSortable = this.enableSorting && column.sortable !== false;

    const cellClasses = {
      'data-grid-header-cell': true,
      'data-grid-header-cell-sortable': isSortable,
      'data-grid-header-cell-sorted': sortDirection !== null,
      [`data-grid-cell-align-${column.align || 'left'}`]: true,
    };

    const cellStyle = column.width
      ? { width: typeof column.width === 'number' ? `${column.width}px` : column.width }
      : {};

    return (
      <div
        class={cellClasses}
        style={cellStyle}
        role="columnheader"
        aria-sort={sortDirection === 'asc' ? 'ascending' : sortDirection === 'desc' ? 'descending' : 'none'}
        onClick={() => isSortable && this.handleSort(column)}
      >
        <span class="data-grid-header-text">
          {column.headerRenderer ? column.headerRenderer(column) : column.header}
        </span>
        {isSortable && sortDirection && (
          <span class="data-grid-sort-icon material-symbols-outlined">
            {sortDirection === 'asc' ? 'arrow_upward' : 'arrow_downward'}
          </span>
        )}
      </div>
    );
  }

  private renderFilterRow() {
    if (!this.enableFiltering || !this.showFilterRow) return null;

    const visibleColumns = this.getVisibleColumns();

    return (
      <div class="data-grid-filter-row" role="row">
        {this.enableSelection && (
          <div class="data-grid-filter-cell data-grid-cell-checkbox" role="cell" />
        )}
        {visibleColumns.map((column) => this.renderFilterCell(column))}
      </div>
    );
  }

  private renderFilterCell(column: DataGridColumn) {
    if (column.filterable === false) {
      return <div class="data-grid-filter-cell" role="cell" />;
    }

    const cellStyle = column.width
      ? { width: typeof column.width === 'number' ? `${column.width}px` : column.width }
      : {};

    const inputValue = this.filterInputValues[column.id] || '';
    const hasFilter = inputValue.trim() !== '';

    // For date columns, use date picker
    if (column.type === 'date') {
      return (
        <div class="data-grid-filter-cell" style={cellStyle} role="cell">
          <div class={{ 'data-grid-filter-icon-wrapper': true, 'data-grid-filter-active': hasFilter }}>
            <bh-date-picker
              variant="dropdown-ghost"
              placeholder=""
              showLabel={false}
              showFooter={false}
              onBhChange={(e: CustomEvent) => {
                const date = e.detail;
                if (date) {
                  const dateStr = `${date.year}-${String(date.month + 1).padStart(2, '0')}-${String(date.day).padStart(2, '0')}`;
                  this.handleFilterInput(column, dateStr);
                } else {
                  this.handleFilterInput(column, '');
                }
              }}
            />
          </div>
        </div>
      );
    }

    // For text/number columns, use search icon with popover input
    return (
      <div class="data-grid-filter-cell" style={cellStyle} role="cell">
        <div class={{ 'data-grid-filter-icon-wrapper': true, 'data-grid-filter-active': hasFilter }}>
          <span
            class="data-grid-filter-icon material-symbols-outlined"
            onClick={() => this.toggleFilterPopover(column.id)}
          >
            search
          </span>
          {this.activeFilterColumn === column.id && (
            <div class="data-grid-filter-popover">
              <input
                type={column.type === 'number' ? 'number' : 'text'}
                class="data-grid-filter-popover-input"
                placeholder={`Filter ${column.header}...`}
                value={inputValue}
                onInput={(e) => this.handleFilterInput(column, (e.target as HTMLInputElement).value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === 'Escape') {
                    this.activeFilterColumn = null;
                  }
                }}
                ref={(el) => el && requestAnimationFrame(() => el.focus())}
              />
            </div>
          )}
        </div>
      </div>
    );
  }

  private renderBody() {
    const processedData = this.getProcessedData();
    const visibleColumns = this.getVisibleColumns();

    if (processedData.length === 0) {
      return this.renderEmptyState();
    }

    // Check if grouping is enabled
    if (this.enableGrouping && this.groupBy.length > 0) {
      const groups = this.getGroupedData(processedData);
      // Use expandedGroups directly in map for proper Stencil reactivity
      const expandedKeys = this.expandedGroups;
      return (
        <div class="data-grid-body" role="rowgroup">
          {groups.map((group) => {
            const isExpanded = expandedKeys.includes(group.key);
            return this.renderGroupSectionWithState(group, visibleColumns, isExpanded);
          })}
        </div>
      );
    }

    return (
      <div class="data-grid-body" role="rowgroup">
        {processedData.map((row, rowIndex) => this.renderRow(row, rowIndex, visibleColumns))}
      </div>
    );
  }

  private renderGroupSectionWithState(group: DataGridGroup, visibleColumns: DataGridColumn[], isExpanded: boolean) {
    const column = this.columns.find(c => c.id === group.columnId);
    const columnHeader = column?.header || group.columnId;

    const sectionClasses = {
      'data-grid-group-section': true,
      'data-grid-group-section-expanded': isExpanded,
    };

    return (
      <div class={sectionClasses} key={group.key}>
        {this.renderGroupRow(group, columnHeader, isExpanded)}
        <div class="data-grid-group-rows" style={{ display: isExpanded ? 'contents' : 'none' }}>
          {group.rows.map((row, rowIndex) => {
            const rowKey = this.getRowKey(row, rowIndex);
            return (
              <div key={`${group.key}-row-${rowKey}`}>
                {this.renderRow(row, rowIndex, visibleColumns, group.depth + 1)}
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  private renderGroupRow(group: DataGridGroup, columnHeader: string, isExpanded: boolean) {
    const groupClasses = {
      'data-grid-group-row': true,
      'data-grid-group-row-expanded': isExpanded,
    };

    const indentStyle = group.depth > 0 ? { paddingLeft: `${(group.depth * 24) + 8}px` } : {};

    return (
      <div
        class={groupClasses}
        style={indentStyle}
        role="row"
        aria-expanded={isExpanded ? 'true' : 'false'}
        onClick={() => this.handleGroupToggle(group.key)}
      >
        {this.enableSelection && (
          <div class="data-grid-cell data-grid-cell-checkbox" role="cell">
            <bh-checkbox
              size="sm"
              checked={this.isGroupAllSelected(group)}
              indeterminate={this.isGroupIndeterminate(group)}
              onBhChange={(e: Event) => {
                e.stopPropagation();
                this.handleGroupSelect(group);
              }}
              onClick={(e: Event) => e.stopPropagation()}
            />
          </div>
        )}
        <div class="data-grid-group-toggle">
          <span class="material-symbols-outlined">
            chevron_right
          </span>
        </div>
        <span class="data-grid-group-label">
          <span class="data-grid-group-column-name">{columnHeader}: </span>
          <span class="data-grid-group-value">{group.displayValue}</span>
        </span>
        <span class="data-grid-group-count">
          ({group.rows.length} {group.rows.length === 1 ? 'item' : 'items'})
        </span>
      </div>
    );
  }

  private isGroupAllSelected(group: DataGridGroup): boolean {
    if (group.rows.length === 0) return false;
    return group.rows.every((row, i) =>
      this.internalSelectedKeys.has(this.getRowKey(row, i))
    );
  }

  private isGroupIndeterminate(group: DataGridGroup): boolean {
    const selectedCount = group.rows.filter((row, i) =>
      this.internalSelectedKeys.has(this.getRowKey(row, i))
    ).length;
    return selectedCount > 0 && selectedCount < group.rows.length;
  }

  private handleGroupSelect = (group: DataGridGroup) => {
    const groupKeys = group.rows.map((row, i) => this.getRowKey(row, i));
    const isAllSelected = this.isGroupAllSelected(group);

    const newSet = new Set(this.internalSelectedKeys);

    if (isAllSelected) {
      // Deselect all in group
      for (const key of groupKeys) {
        newSet.delete(key);
      }
    } else {
      // Select all in group
      for (const key of groupKeys) {
        newSet.add(key);
      }
    }

    this.internalSelectedKeys = newSet;
    this.emitSelectionChange();
  };

  // -------------------------------------------------------------------------
  // Editing Handlers
  // -------------------------------------------------------------------------

  private startEditing = (row: unknown, rowIndex: number, columnId?: string) => {
    if (!this.enableEditing) return;

    const rowKey = this.getRowKey(row, rowIndex);

    // Initialize editing values from current row
    const initialValues: Record<string, unknown> = {};
    for (const col of this.columns) {
      if (col.editable !== false) {
        initialValues[col.id] = this.getCellValue(row, col.accessor as string);
      }
    }

    this.editingRowKey = rowKey;
    this.editingColumnId = this.editMode === 'cell' ? (columnId || null) : null;
    this.editingValues = initialValues;

    if (this.editMode === 'popup') {
      this.showEditPopup = true;
    }

    this.bhEditStart.emit({ rowKey, row, columnId });
  };

  private cancelEditing = () => {
    if (this.editingRowKey === null) return;

    const row = this.data.find((r, i) => this.getRowKey(r, i) === this.editingRowKey);

    this.bhEditCancel.emit({ rowKey: this.editingRowKey, row });

    this.editingRowKey = null;
    this.editingColumnId = null;
    this.editingValues = {};
    this.showEditPopup = false;
  };

  private saveEditing = () => {
    if (this.editingRowKey === null) return;

    const rowIndex = this.data.findIndex((r, i) => this.getRowKey(r, i) === this.editingRowKey);
    if (rowIndex === -1) return;

    const originalRow = this.data[rowIndex];
    const changes: Record<string, unknown> = {};

    // Determine what changed
    for (const [columnId, newValue] of Object.entries(this.editingValues)) {
      const column = this.columns.find(c => c.id === columnId);
      if (column) {
        const originalValue = this.getCellValue(originalRow, column.accessor as string);
        if (originalValue !== newValue) {
          changes[columnId] = newValue;
        }
      }
    }

    this.bhEditSave.emit({
      rowKey: this.editingRowKey,
      rowIndex,
      originalRow,
      changes,
    });

    this.editingRowKey = null;
    this.editingColumnId = null;
    this.editingValues = {};
    this.showEditPopup = false;
  };

  private handleEditValueChange = (columnId: string, newValue: unknown) => {
    const oldValue = this.editingValues[columnId];

    this.editingValues = {
      ...this.editingValues,
      [columnId]: newValue,
    };

    if (this.editingRowKey !== null) {
      this.bhCellChange.emit({
        rowKey: this.editingRowKey,
        columnId,
        oldValue,
        newValue,
      });
    }
  };

  private isEditing(rowKey: string | number, columnId?: string): boolean {
    if (this.editingRowKey !== rowKey) return false;

    if (this.editMode === 'cell') {
      return columnId ? this.editingColumnId === columnId : false;
    }

    // Row or popup mode - entire row is in edit mode
    return true;
  }

  private handleCellDoubleClick = (row: unknown, column: DataGridColumn, rowIndex: number) => {
    if (!this.enableEditing || column.editable === false) return;

    if (this.editMode === 'cell') {
      this.startEditing(row, rowIndex, column.id);
    }
  };

  private handleEditKeyDown = (event: KeyboardEvent, column: DataGridColumn) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      if (this.editMode === 'cell') {
        this.saveEditing();
      }
    } else if (event.key === 'Escape') {
      event.preventDefault();
      this.cancelEditing();
    } else if (event.key === 'Tab' && this.editMode === 'cell') {
      // Move to next editable cell
      event.preventDefault();
      this.moveToNextEditableCell(column, event.shiftKey);
    }
  };

  private moveToNextEditableCell = (currentColumn: DataGridColumn, reverse: boolean) => {
    const editableColumns = this.columns.filter(c => c.editable !== false && c.visible !== false);
    const currentIndex = editableColumns.findIndex(c => c.id === currentColumn.id);

    if (currentIndex === -1) return;

    const nextIndex = reverse ? currentIndex - 1 : currentIndex + 1;

    if (nextIndex >= 0 && nextIndex < editableColumns.length) {
      // Same row, different column
      this.editingColumnId = editableColumns[nextIndex].id;
    } else {
      // Save and potentially move to next/prev row
      this.saveEditing();
    }
  };

  // -------------------------------------------------------------------------
  // Render Methods
  // -------------------------------------------------------------------------

  private renderRow(row: unknown, rowIndex: number, visibleColumns: DataGridColumn[], depth: number = 0) {
    const rowKey = this.getRowKey(row, rowIndex);
    const isSelected = this.internalSelectedKeys.has(rowKey);
    const isHovered = this.hoveredRowIndex === rowIndex;
    const isRowEditing = this.editingRowKey === rowKey;

    const rowClasses = {
      'data-grid-row': true,
      'data-grid-row-selected': isSelected,
      'data-grid-row-hover': isHovered,
      'data-grid-row-striped': this.striped && rowIndex % 2 === 1,
      'data-grid-row-grouped': depth > 0,
      'data-grid-row-editing': isRowEditing,
    };

    return (
      <div
        class={rowClasses}
        role="row"
        aria-selected={isSelected ? 'true' : 'false'}
        onMouseEnter={() => { this.hoveredRowIndex = rowIndex; }}
        onMouseLeave={() => { this.hoveredRowIndex = null; }}
        onClick={() => this.handleRowClick(row, rowIndex)}
      >
        {this.enableSelection && (
          <div
            class="data-grid-cell data-grid-cell-checkbox"
            role="cell"
            onClick={(e) => { e.stopPropagation(); }}
          >
            <bh-checkbox
              size="sm"
              checked={isSelected}
              onBhChange={() => this.handleRowSelect(row, rowIndex)}
              onClick={(e: Event) => e.stopPropagation()}
            />
          </div>
        )}
        {depth > 0 && (
          <div class="data-grid-row-indent" style={{ width: `${depth * 24}px` }} />
        )}
        {visibleColumns.map((column, columnIndex) => this.renderCell(row, column, rowIndex, columnIndex))}
        {this.enableEditing && this.showEditActions && this.renderRowActions(row, rowIndex, isRowEditing)}
      </div>
    );
  }

  private renderRowActions(row: unknown, rowIndex: number, isEditing: boolean) {
    return (
      <div class="data-grid-cell data-grid-cell-actions" role="cell" onClick={(e) => e.stopPropagation()}>
        {isEditing ? (
          <div class="data-grid-edit-actions">
            <button
              class="data-grid-action-btn data-grid-action-save"
              onClick={() => this.saveEditing()}
              title="Save"
            >
              <span class="material-symbols-outlined">check</span>
            </button>
            <button
              class="data-grid-action-btn data-grid-action-cancel"
              onClick={() => this.cancelEditing()}
              title="Cancel"
            >
              <span class="material-symbols-outlined">close</span>
            </button>
          </div>
        ) : (
          <button
            class="data-grid-action-btn data-grid-action-edit"
            onClick={() => this.startEditing(row, rowIndex)}
            title="Edit"
          >
            <span class="material-symbols-outlined">edit</span>
          </button>
        )}
      </div>
    );
  }

  private renderCell(row: unknown, column: DataGridColumn, rowIndex: number, columnIndex: number) {
    const rowKey = this.getRowKey(row, rowIndex);
    const value = this.getCellValue(row, column.accessor as string);
    const isEditingCell = this.isEditing(rowKey, column.id);
    const canEdit = this.enableEditing && column.editable !== false;

    const cellClasses = {
      'data-grid-cell': true,
      [`data-grid-cell-align-${column.align || 'left'}`]: true,
      [`data-grid-cell-type-${column.type || 'text'}`]: true,
      'data-grid-cell-editing': isEditingCell,
      'data-grid-cell-editable': canEdit && !isEditingCell,
    };

    const cellStyle = column.width
      ? { width: typeof column.width === 'number' ? `${column.width}px` : column.width }
      : {};

    return (
      <div
        class={cellClasses}
        style={cellStyle}
        role="cell"
        onClick={(e) => {
          e.stopPropagation();
          this.handleCellClick(row, column, rowIndex, columnIndex);
        }}
        onDblClick={(e) => {
          e.stopPropagation();
          this.handleCellDoubleClick(row, column, rowIndex);
        }}
      >
        {isEditingCell
          ? this.renderEditInput(column, value)
          : column.cellRenderer
            ? column.cellRenderer(value, row as never, rowIndex)
            : this.formatCellValue(value, column.type)
        }
      </div>
    );
  }

  private renderEditInput(column: DataGridColumn, originalValue: unknown) {
    const currentValue = this.editingValues[column.id] ?? originalValue;

    // Custom edit renderer takes precedence
    if (column.editCellRenderer) {
      return column.editCellRenderer(
        currentValue,
        {} as never, // row not needed for most custom renderers
        0,
        (newValue: unknown) => this.handleEditValueChange(column.id, newValue)
      );
    }

    const inputType = column.type === 'number' ? 'number' :
                      column.type === 'date' ? 'date' :
                      column.type === 'boolean' ? 'checkbox' : 'text';

    if (column.type === 'boolean') {
      return (
        <bh-checkbox
          size="sm"
          checked={Boolean(currentValue)}
          onBhChange={(e: CustomEvent) => this.handleEditValueChange(column.id, e.detail.checked)}
        />
      );
    }

    return (
      <input
        type={inputType}
        class="data-grid-edit-input"
        value={currentValue != null ? String(currentValue) : ''}
        onInput={(e) => {
          const input = e.target as HTMLInputElement;
          const newValue = column.type === 'number' ? Number(input.value) : input.value;
          this.handleEditValueChange(column.id, newValue);
        }}
        onKeyDown={(e) => this.handleEditKeyDown(e, column)}
        ref={(el) => {
          if (el) {
            // Auto-focus on the first editable input
            requestAnimationFrame(() => el.focus());
          }
        }}
      />
    );
  }

  private formatCellValue(value: unknown, type?: DataGridColumnType): string {
    if (value === null || value === undefined) return '';

    switch (type) {
      case 'date':
        return new Date(value as string).toLocaleDateString();
      case 'number':
        return typeof value === 'number' ? value.toLocaleString() : String(value);
      case 'boolean':
        return value ? 'Yes' : 'No';
      default:
        return String(value);
    }
  }

  private renderEmptyState() {
    return (
      <div class="data-grid-empty-state">
        <bh-empty-state
          emptyTitle="No data"
          description={this.emptyMessage}
        />
      </div>
    );
  }

  private renderLoading() {
    return (
      <div class="data-grid-loading-overlay">
        <bh-loader-spinner size="lg" />
      </div>
    );
  }

  // -------------------------------------------------------------------------
  // Main Render
  // -------------------------------------------------------------------------

  render() {
    const gridClasses = {
      'data-grid': true,
      'data-grid-compact': this.compact,
      'data-grid-bordered': this.showRowBorders,
      'data-grid-loading': this.loading,
    };

    return (
      <div class={gridClasses} role="grid" aria-busy={this.loading ? 'true' : 'false'}>
        <div class="data-grid-table">
          {this.renderHeader()}
          {this.renderFilterRow()}
          {this.renderBody()}
        </div>
        {this.loading && this.renderLoading()}
      </div>
    );
  }
}
